# -*- coding: utf-8 -*-"""This script plots the image for figure3"""import matplotlib.pyplot as plt# --- allow running this file directly: put repo root on sys.path ---import os as _os, sys as _sys_root = _os.path.dirname(_os.path.abspath(__file__))while not _os.path.isdir(_os.path.join(_root, "src")) and _root != _os.path.dirname(_root):    _root = _os.path.dirname(_root)if _root not in _sys.path:    _sys.path.insert(0, _root)# ------------------------------------------------------------------from src import pathsimport cv2import src.tools.plot_tools as plot_tools# first imageclass4_1 = paths.DAT + "class4_1.png"class4_1 = cv2.imread(class4_1)x, y = 600, 600size = int(1000/2)crop_img_1 = class4_1[x-size:x+size, y-size:y+size]crop_img_1 = cv2.cvtColor(crop_img_1, cv2.COLOR_BGR2RGB)plt.imshow(crop_img_1)#%%# second imageclass4_2 = paths.DAT + "class4_2.png"class4_2 = cv2.imread(class4_2)x, y = 600, 650size = int(1000/2)crop_img_2 = class4_2[x-size:x+size, y-size:y+size]crop_img_2 = cv2.cvtColor(crop_img_2, cv2.COLOR_BGR2RGB)plt.imshow(crop_img_2)#%%# second imageclass4_3 = paths.DAT + "class4_3.png"class4_3 = cv2.imread(class4_3)x, y = 500, 500size = int(800/2)crop_img_3 = class4_3[x-size:x+size, y-size:y+size]crop_img_3 = cv2.cvtColor(crop_img_3, cv2.COLOR_BGR2RGB)plt.imshow(crop_img_3)#%%f = plt.figure(figsize=(11, 9), dpi = 300)ax1 = f.add_subplot(331)ax2 = f.add_subplot(332)ax3 = f.add_subplot(333)ax1.imshow(crop_img_1)ax2.imshow(crop_img_2)ax3.imshow(crop_img_3)for ax in [ax1, ax2, ax3]:    ax.set_yticklabels([])    ax.set_xticklabels([])    ax.tick_params(axis='both', which = 'major', direction = 'in',length = 6, width = 1)    ax.tick_params(axis='both', which = 'minor', direction = 'in',length = 4, width =1)    ax.yaxis.set_ticks_position('both')    ax.xaxis.set_ticks_position('both')plt.tight_layout(pad = -3)plot_tools.save("class4_inspect")